import{_ as e,o as a,c as i,a2 as s}from"./chunks/framework.BtKjyiyt.js";const g=JSON.parse('{"title":"Documents & Citations","description":"","frontmatter":{},"headers":[],"relativePath":"documents.md","filePath":"documents.md","lastUpdated":null}'),n={name:"documents.md"};function o(l,t,r,d,h,c){return a(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="Documents-and-Citations" tabindex="-1">Documents &amp; Citations <a class="header-anchor" href="#Documents-and-Citations" aria-label="Permalink to &quot;Documents &amp; Citations {#Documents-and-Citations}&quot;">​</a></h1><p>A notebook is also a <strong>publishable document</strong>. Beyond code and prose it can carry academic front matter — a title block, an abstract, a bibliography — and cite sources inline. Every export target (article/report PDF, slide deck, HTML, a published site) reads the same authored metadata and places it correctly.</p><p>You author document metadata as <strong>ordinary cells</strong> carrying a <em>role tag</em> (set with the 🏷 <a href="./cell-tags">tag editor</a> or a token in the cell header), in natural reading order. Nothing is a special syntax — a <code>title</code> cell is just a markdown cell that the export hoists.</p><h2 id="Front-matter" tabindex="-1">Front matter <a class="header-anchor" href="#Front-matter" aria-label="Permalink to &quot;Front matter {#Front-matter}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Role tag</th><th style="text-align:right;">The cell becomes</th><th style="text-align:right;">Placement on export</th></tr></thead><tbody><tr><td style="text-align:right;"><code>title</code></td><td style="text-align:right;">the title block: <code># Title</code>, then <code>##</code>/<code>###</code> subtitle, then the first plain line as byline</td><td style="text-align:right;">hoisted to the top</td></tr><tr><td style="text-align:right;"><code>abstract</code></td><td style="text-align:right;">an academic abstract</td><td style="text-align:right;">hoisted into the title block</td></tr><tr><td style="text-align:right;"><code>bibliography</code></td><td style="text-align:right;">the reference database (see below)</td><td style="text-align:right;">not shown; drives citations + References</td></tr></tbody></table><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#%% md id=fm title</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Spectral Methods for the Heat Equation</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">### A reproducible study</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Ada Lovelace </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">·</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Analytical Engine Lab</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#%% md id=abs abstract</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">We compare Chebyshev and Fourier spectral discretizations on the </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">D heat</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">equation, and show the reactive notebook that produced every figure.</span></span></code></pre></div><p>With no <code>title</code> cell, the document title falls back to the first markdown <code># H1</code>, then the filename. The title block also feeds the PDF/HTML title, the <a href="./publishing">published-site</a> card, and the OG social-card metadata.</p><h2 id="bibliography" tabindex="-1">Bibliography <a class="header-anchor" href="#bibliography" aria-label="Permalink to &quot;Bibliography&quot;">​</a></h2><p>Tag a markdown cell <code>bibliography</code>. Its body is either <strong>embedded BibTeX</strong> or one-or-more <strong><code>.bib</code> file paths</strong> (one per line, resolved relative to the notebook and copied into exports). Inline and external entries can be mixed.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#%% md id=bib bibliography</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@book</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{knuth1984,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  author </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {Donald E. Knuth},</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  title  </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {The TeXbook},</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  year   </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1984</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  publisher </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {Addison</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Wesley}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">references</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bib</span></span></code></pre></div><p>In the live notebook, the bibliography renders an adaptive <strong>references card</strong> listing your entries, with the keys you&#39;ve actually cited highlighted.</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/references-card.png" alt=""></p><h2 id="Citing-in-prose" tabindex="-1">Citing in prose <a class="header-anchor" href="#Citing-in-prose" aria-label="Permalink to &quot;Citing in prose {#Citing-in-prose}&quot;">​</a></h2><p>Cite a bibliography key from any <strong>markdown</strong> cell. Typing <code>[@</code> autocompletes keys.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Form</th><th style="text-align:right;">Renders (numeric style)</th><th style="text-align:right;">Use</th></tr></thead><tbody><tr><td style="text-align:right;"><code>[@knuth1984]</code></td><td style="text-align:right;"><code>[1]</code></td><td style="text-align:right;">a normal citation</td></tr><tr><td style="text-align:right;"><code>[@knuth1984, pp. 33-35]</code></td><td style="text-align:right;"><code>[1, pp. 33–35]</code></td><td style="text-align:right;">with a page/locator</td></tr><tr><td style="text-align:right;"><code>[@a; @b]</code></td><td style="text-align:right;"><code>[1, 2]</code></td><td style="text-align:right;">several at once</td></tr><tr><td style="text-align:right;"><code>@knuth1984</code></td><td style="text-align:right;"><code>Knuth (1984)</code></td><td style="text-align:right;">a prose (author–year) mention</td></tr></tbody></table><p>The bare <code>@key</code> prose form only converts keys that are actually defined, so an email address or a stray <code>@handle</code> stays literal. On export, citations render <strong>linked</strong> to the References section and a References list is generated in your chosen style; the live notebook mirrors this with the references card.</p><h2 id="Citation-style" tabindex="-1">Citation style <a class="header-anchor" href="#Citation-style" aria-label="Permalink to &quot;Citation style {#Citation-style}&quot;">​</a></h2><p>Set the citation style per notebook in <strong>Settings → Citation style</strong> (persisted as <code>bibstyle</code> in the <a href="/KaimonSlate.jl/previews/PR9/configuration#notebook-config">Notebook config</a>):</p><p><code>ieee</code> · <code>apa</code> · <code>chicago-author-date</code> · <code>mla</code> · <code>nature</code> · <code>vancouver</code> · <code>harvard</code></p><p>Numeric styles (IEEE, Nature, Vancouver) render <code>[1]</code> and order the References by first citation; author–date styles (APA, Chicago, MLA, Harvard) render <code>(Knuth, 1984)</code> and order alphabetically.</p><h2 id="figures" tabindex="-1">Figures <a class="header-anchor" href="#figures" aria-label="Permalink to &quot;Figures&quot;">​</a></h2><p>Markdown caption cells become <strong>numbered figures</strong> on export (<code>Figure N.</code>), and a reference to a figure label links to it — the same cross-reference machinery as citations. Figures embed as vectors where possible (CairoMakie → PDF, ECharts → SVG) so they stay crisp in print. See <a href="./export">Export</a> and <a href="./visualization">Charts &amp; Tables</a>.</p><div class="tip custom-block"><p class="custom-block-title">From notebook to paper</p><p>Add a <code>title</code> cell, an <code>abstract</code> cell, and a <code>bibliography</code> cell; cite with <code>[@key]</code>; then <strong>Export → PDF (Report, two-column)</strong>. The same notebook is your working analysis <em>and</em> the manuscript that reproduces it.</p></div>`,23)])])}const k=e(n,[["render",o]]);export{g as __pageData,k as default};
